query GetOrders($status: OrderStatus, $page: Int, $pageSize: Int) {
  orders(status: $status, page: $page, pageSize: $pageSize) {
    data {
      id status createdAt
      customer { name phone }
      items { id name quantity unitPrice }
      totalAmount currency
    }
    pagination { page pageSize totalItems hasNext }
  }
}

query GetOrder($id: ID!) {
  order(id: $id) {
    id status createdAt updatedAt
    customer { name phone }
    items { id name quantity unitPrice totalPrice notes }
    totalAmount currency
    payment { method status brand }
    deliveryAddress { street number city state zipcode }
    statusHistory { status timestamp }
  }
}

mutation ConfirmOrder($id: ID!, $input: ConfirmOrderInput!) {
  confirmOrder(id: $id, input: $input) {
    id status estimatedReadyAt confirmedAt
  }
}

mutation UpdateOrderStatus($id: ID!, $input: UpdateStatusInput!) {
  updateOrderStatus(id: $id, input: $input) {
    id status previousStatus updatedAt
  }
}

mutation CancelOrder($id: ID!, $input: CancelOrderInput!) {
  cancelOrder(id: $id, input: $input) {
    id status cancelledAt cancellationReason
    refund { status amount estimatedDate }
  }
}
